import { CustomElement } from 'custom-elements-ts';

declare const Prism: {
  highlight(code: string, grammar: unknown): string;
  languages: {
    typescript: unknown;
    javascript: unknown;
  };
};

@CustomElement({
  tag: 'cts-code-example',
  template: '<div id="code"></div>',
  style: `/* Lives inside <article class="window">; the chrome owns background + radius. */

:host {
  display: block;
  padding: 22px 26px 26px;
  font-family: "Geist Mono", "JetBrains Mono", ui-monospace, SFMono-Regular,
               Menlo, Consolas, "Courier New", monospace;
  font-size: 13.5px;
  line-height: 1.65;
  color: #d6dce5;
  background: transparent;
  overflow-x: auto;
  max-height: 520px;
  -webkit-font-smoothing: antialiased;

  @media (min-width: 980px) {
    font-size: 14px;
    padding: 28px 32px 32px;
  }

  /* Custom scrollbar so the code area doesn't ship a chunky default bar */
  scrollbar-width: thin;
  scrollbar-color: rgba(255, 255, 255, 0.10) transparent;

  &::-webkit-scrollbar {
    height: 8px;
    width: 8px;
  }
  &::-webkit-scrollbar-thumb {
    background: rgba(255, 255, 255, 0.10);
    border-radius: 2px;
  }
  &::-webkit-scrollbar-track { background: transparent; }
}

pre,
pre[class*="language-"] {
  margin: 0;
  padding: 0;
  background: transparent;
  border: 0;
  border-radius: 0;
  color: inherit;
  font-family: inherit;
  font-size: inherit;
  line-height: inherit;
  text-shadow: none;
  white-space: pre;
  word-spacing: normal;
  word-break: normal;
  -moz-tab-size: 2;
  -o-tab-size: 2;
  tab-size: 2;
  hyphens: none;
  overflow: visible;
}

code,
code[class*="language-"] {
  background: transparent;
  color: inherit;
  font-family: inherit;
  font-size: inherit;
  line-height: inherit;
  text-shadow: none;
  white-space: pre;
}

/* ─── Prism token theme — VS Code "Dark Modern" inspired, TS blue led ─── */

.token {
  &.comment,
  &.prolog,
  &.doctype,
  &.cdata {
    color: #6e7681;
    font-style: italic;
  }

  &.punctuation {
    color: #c9d1d9;
  }

  /* identifier-blue — properties, tags, attribute-name (e.g. tag:, template:) */
  &.property,
  &.tag,
  &.attr-name {
    color: #9cdcfe;
  }

  /* TS-blue — keywords (import, export, class, extends, new) */
  &.keyword,
  &.boolean {
    color: #4189d6;
  }

  /* teal — class names, types */
  &.class-name {
    color: #4ec9b0;
  }

  &.constant,
  &.symbol {
    color: #4189d6;
  }

  /* light green — numbers */
  &.number {
    color: #b5cea8;
  }

  /* warm muted — strings (the only "warm" color, used sparingly) */
  &.string,
  &.char,
  &.attr-value,
  &.builtin,
  &.inserted {
    color: #ce9178;
  }

  /* selectors stay muted */
  &.selector {
    color: #d7ba7d;
  }

  &.variable {
    color: #d6dce5;
  }

  &.operator,
  &.entity {
    color: #d6dce5;
  }

  &.url {
    color: #4189d6;
    text-decoration: underline;
  }

  &.atrule {
    color: #c586c0;
  }

  /* function names — soft cream so they don't fight the blues */
  &.function {
    color: #dcdcaa;
  }

  &.regex {
    color: #d16969;
  }

  &.important {
    color: #f47067;
    font-weight: 600;
  }

  &.bold { font-weight: 600; }
  &.italic { font-style: italic; }
  &.deleted { color: #f47067; }
}

.namespace { opacity: .65; }

.language-css .token.string,
.style .token.string {
  color: #ce9178;
}
`,
})
export class CodeExampleElement extends HTMLElement {
  // Mirrors the real cts-message element rendered in the install card on this
  // page. Keeping these in sync is intentional: the source you see is the
  // source that runs the toast you triggered.
  private readonly source = `import {
  CustomElement,
  Prop,
  Listen,
  Dispatch,
  DispatchEmitter,
} from 'custom-elements-ts';

@CustomElement({
  tag: 'cts-message',
  template: \`
    <div class="row" role="button" tabindex="0">
      <span class="prompt" aria-hidden="true">$</span>
      <code class="cmd"></code>
    </div>
  \`,
  styleUrl: './message.element.scss',
})
export class MessageElement extends HTMLElement {
  @Prop() message!: string;

  // Bubbling, composed CustomEvent — the host page can listen on
  // any ancestor (including <cts-toast>) without piercing shadow DOM.
  @Dispatch('cts:toast') toast!: DispatchEmitter;

  @Listen('click')
  async handleClick() {
    const ok = await this.copy(this.message);
    this.toast.emit({
      bubbles: true,
      composed: true,
      detail: ok
        ? { title: 'Copied to clipboard', message: this.message, kind: 'success' }
        : { title: "Couldn't copy", message: 'Copy manually.', kind: 'error' },
    });
  }

  connectedCallback() {
    this.shadowRoot!.querySelector('.cmd')!.textContent = this.message;
  }

  private async copy(text: string): Promise<boolean> {
    try {
      await navigator.clipboard.writeText(text);
      return true;
    } catch {
      return false;
    }
  }
}

// Drop it anywhere — React, Vue, Svelte, plain HTML — it just works:
<cts-message message="npm install custom-elements-ts"></cts-message>`;

  private code = '';

  constructor() {
    super();
    const grammar = Prism.languages.typescript ?? Prism.languages.javascript;
    this.code = Prism.highlight(this.source, grammar);
  }

  connectedCallback() {
    const code = this.shadowRoot?.querySelector('#code');
    if (code) {
      code.innerHTML = `<pre><code>${this.code}</code></pre>`;
    }
  }
}
