import {
  CustomElement,
  Prop,
  State,
  TemplateResult,
  Watch,
  html,
} from 'custom-elements-ts';

interface LogEntry {
  id: number;
  name: string;
  detail: string;
  time: string;
}

const MAX_ENTRIES = 6;

/**
 * Tiny "what just happened" panel used on the showcase page.
 *
 * Subscribes to one or more bubbling, composed CustomEvents at the document
 * level and renders the most recent few. Pure render() / @State() — no manual
 * DOM diffing — so it doubles as a live example of the templating runtime.
 */
@CustomElement({
  tag: 'cts-event-log',
  style: `/* ─────────────────────────────────────────────────────────────
   <cts-event-log>
   Sits beside live demos on the showcase page; renders the most
   recent CustomEvents the demo has dispatched. Tokens mirror the
   site's design system (TS-blue accent, sharp 2–4px radii).
   ───────────────────────────────────────────────────────────── */

:host {
  /* Mirror the site tokens so we don't rely on inheritance through
     the shadow boundary. */
  --bg: #0a0c10;
  --bg-elev-1: #11141a;
  --bg-elev-2: #161a22;
  --line: rgba(255, 255, 255, 0.06);
  --line-strong: rgba(255, 255, 255, 0.10);
  --fg: #e6ecf3;
  --fg-muted: #97a1ad;
  --fg-subtle: #5b6370;
  --accent: #3178c6;
  --accent-bright: #4189d6;
  --accent-fg: #9cc0eb;
  --accent-soft: rgba(49, 120, 198, 0.14);
  --accent-line: rgba(49, 120, 198, 0.42);

  --radius-xs: 2px;
  --radius-sm: 2px;
  --radius-md: 3px;

  --ease: cubic-bezier(0.22, 1, 0.36, 1);
  --dur-fast: 140ms;
  --dur: 220ms;

  display: flex;
  flex-direction: column;
  min-height: 240px;
  padding: 14px 16px 16px;
  border: 1px solid var(--line-strong);
  border-radius: var(--radius-md);
  background:
    radial-gradient(140% 100% at 0% 0%, rgba(49, 120, 198, 0.05) 0%, transparent 60%),
    linear-gradient(180deg, var(--bg-elev-1) 0%, #0f131b 100%);
  color: var(--fg);
  font-family: "Geist", "Inter", ui-sans-serif, system-ui, -apple-system,
               "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
  -webkit-font-smoothing: antialiased;
}

* { box-sizing: border-box; }

/* ── Header ─────────────────────────────────────────────── */

.head {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 10px;
  padding-bottom: 10px;
  border-bottom: 1px solid var(--line);
}

.dot {
  width: 6px;
  height: 6px;
  background: var(--accent);
  box-shadow: 0 0 10px var(--accent-line);
}

.label {
  flex: 1 1 auto;
  font-family: "Geist Mono", "JetBrains Mono", ui-monospace, SFMono-Regular,
               Menlo, Consolas, "Courier New", monospace;
  font-size: 11px;
  font-weight: 500;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: var(--fg-muted);
}

.count {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 22px;
  height: 18px;
  padding: 0 6px;
  border: 1px solid var(--line-strong);
  border-radius: var(--radius-xs);
  background: rgba(255, 255, 255, 0.02);
  color: var(--accent-fg);
  font-family: "Geist Mono", "JetBrains Mono", ui-monospace, SFMono-Regular,
               Menlo, Consolas, "Courier New", monospace;
  font-size: 10px;
  font-weight: 600;
  font-variant-numeric: tabular-nums;
}

/* ── Empty ───────────────────────────────────────────── */

.empty {
  margin: auto 0;
  padding: 12px 4px;
  color: var(--fg-subtle);
  font-size: 12.5px;
  line-height: 1.55;
  text-wrap: balance;
}

/* ── List ───────────────────────────────────────────── */

.list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.entry {
  position: relative;
  display: grid;
  grid-template-columns: auto auto 1fr;
  align-items: center;
  gap: 10px;
  padding: 7px 8px;
  border: 1px solid var(--line);
  border-radius: var(--radius-xs);
  background: rgba(255, 255, 255, 0.015);
  font-family: "Geist Mono", "JetBrains Mono", ui-monospace, SFMono-Regular,
               Menlo, Consolas, "Courier New", monospace;
  font-size: 11.5px;
  font-variant-numeric: tabular-nums;
  animation: entry-in 220ms var(--ease) both;
}

.entry::before {
  content: "";
  position: absolute;
  left: -1px;
  top: -1px;
  bottom: -1px;
  width: 2px;
  background: var(--accent);
  opacity: 0.85;
}

.entry-time {
  color: var(--fg-subtle);
  letter-spacing: 0.02em;
}

.entry-name {
  color: var(--accent-fg);
  font-weight: 500;
  white-space: nowrap;
}

.entry-detail {
  min-width: 0;
  color: var(--fg-muted);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

@keyframes entry-in {
  from {
    opacity: 0;
    transform: translateY(-3px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@media (prefers-reduced-motion: reduce) {
  .entry { animation: none; }
}
`,
})
export class EventLogElement extends HTMLElement {
  /** Comma-separated list of event names to subscribe to on `document`. */
  @Prop() events = '';
  /** Optional human label rendered above the list. */
  @Prop() label = 'Event log';
  /** Optional empty-state copy. */
  @Prop() empty = 'Interact with the component above to see events stream in.';

  @State() entries: LogEntry[] = [];

  private subscriptions: Array<{ name: string; handler: EventListener }> = [];
  private nextId = 1;

  connectedCallback() {
    this.bind();
  }

  disconnectedCallback() {
    this.unbind();
  }

  @Watch('events')
  rebind() {
    this.unbind();
    this.bind();
  }

  render(): TemplateResult {
    const entries = this.entries;
    return html`
      <header class="head">
        <span class="dot" aria-hidden="true"></span>
        <span class="label">${this.label}</span>
        <span class="count" aria-hidden="true">${entries.length}</span>
      </header>

      ${entries.length === 0
        ? html`<p class="empty">${this.empty}</p>`
        : html`<ol class="list" aria-live="polite">
            ${entries.map(
              (entry) => html`
                <li class="entry" data-id=${entry.id}>
                  <span class="entry-time">${entry.time}</span>
                  <span class="entry-name">${entry.name}</span>
                  <span class="entry-detail">${entry.detail}</span>
                </li>
              `
            )}
          </ol>`}
    `;
  }

  private bind() {
    const names = this.events
      .split(',')
      .map((name) => name.trim())
      .filter(Boolean);

    for (const name of names) {
      const handler: EventListener = (event) => this.record(name, event as CustomEvent);
      document.addEventListener(name, handler);
      this.subscriptions.push({ name, handler });
    }
  }

  private unbind() {
    for (const { name, handler } of this.subscriptions) {
      document.removeEventListener(name, handler);
    }
    this.subscriptions = [];
  }

  private record(name: string, event: CustomEvent) {
    const entry: LogEntry = {
      id: this.nextId++,
      name,
      detail: this.formatDetail(event.detail),
      time: this.timestamp(),
    };
    // Newest first, capped to MAX_ENTRIES so the panel never grows unbounded.
    this.entries = [entry, ...this.entries].slice(0, MAX_ENTRIES);
  }

  private formatDetail(detail: unknown): string {
    if (detail == null) return '—';
    if (typeof detail === 'string') return detail;
    if (typeof detail === 'number' || typeof detail === 'boolean') {
      return String(detail);
    }
    try {
      return JSON.stringify(detail);
    } catch {
      return String(detail);
    }
  }

  private timestamp(): string {
    const now = new Date();
    const pad = (value: number, size = 2) => String(value).padStart(size, '0');
    return `${pad(now.getHours())}:${pad(now.getMinutes())}:${pad(now.getSeconds())}.${pad(
      now.getMilliseconds(),
      3
    )}`;
  }
}
